// Debounce function to limit the rate at which a function is called.
function debounce(func, delay) {
    let timeoutId;
    return function(...args) {
        if (timeoutId) clearTimeout(timeoutId);
        timeoutId = setTimeout(() => func.apply(this, args), delay);
    };
}

// Example usage:
const handleResize = () => console.log('Window resized!');
const debouncedHandleResize = debounce(handleResize, 300);

window.addEventListener('resize', debouncedHandleResize);
```

This `debounce` function delays the execution of a function until a specified amount of time has elapsed since the last time it was invoked, which is useful for optimizing performance in scenarios like resize or scroll events.
